import React from "react";
import {
  AssistantRuntimeProvider,
  useLocalRuntime,
} from "@assistant-ui/react";

const API_BASE_URL = "http://localhost:8000";

// Simple adapter that calls your existing FastAPI /api/chat endpoint.
const chatModelAdapter = {
  async run({ messages, abortSignal }) {
    // Flatten assistant-ui message parts into simple { role, content } objects
    const toPlainMessages = (msgs) =>
      msgs
        .filter((m) => m.role === "user" || m.role === "assistant")
        .map((m) => ({
          role: m.role,
          content: (m.content || [])
            .filter((part) => part.type === "text" && typeof part.text === "string")
            .map((part) => part.text)
            .join(" ")
            .trim(),
        }))
        .filter((m) => m.content.length > 0);

    const plainMessages = toPlainMessages(messages);

    const lastUser = [...plainMessages].reverse().find((m) => m.role === "user");
    if (!lastUser) {
      return { content: [] };
    }

    const lastUserIndex = plainMessages.lastIndexOf(lastUser);
    const conversation_history = plainMessages.slice(0, lastUserIndex + 1);

    let response;
    try {
      response = await fetch(`${API_BASE_URL}/api/chat`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          message: lastUser.content,
          session_id: `ui-${Date.now()}`,
          conversation_history,
        }),
        signal: abortSignal,
      });
    } catch (err) {
      if (err.name === "AbortError") throw err;
      return {
        content: [
          {
            type: "text",
            text:
              "Could not connect to the AI Doctor backend. Start it with: uvicorn app.main:app --reload --port 8000",
          },
        ],
      };
    }

    if (!response.ok) {
      const errorText = await response.text().catch(() => "");
      return {
        content: [
          {
            type: "text",
            text:
              "Sorry, I couldn’t reach the server. Please make sure the backend is running (e.g. `uvicorn app.main:app --reload --port 8000`). " +
              (errorText ? `Details: ${errorText}` : `HTTP ${response.status}`),
          },
        ],
      };
    }

    const data = await response.json();

    return {
      // This shape is what assistant-ui expects from a ChatModelAdapter
      content: [
        {
          type: "text",
          text: data.reply ?? "",
        },
      ],
    };
  },
};

export function MyRuntimeProvider({ children }) {
  const runtime = useLocalRuntime(chatModelAdapter, {});

  return (
    <AssistantRuntimeProvider runtime={runtime}>{children}</AssistantRuntimeProvider>
  );
}

